-- RADIOLEDGER REFERENCE DATA
-- NOTE: This reference data is now included in 001_initial_schema.sql.
-- This file is kept for standalone seeding/re-seeding outside of migrations.
-- Consolidated from seed files 001_bands.sql, 002_modes.sql, 003_dxcc_entities.sql.
-- ═══════════════════════════════════════════════════════════════════════════════


-- ─────────────────────────────────────────────────────────────────────────────
-- BANDS
-- Frequencies are in MHz.
-- ─────────────────────────────────────────────────────────────────────────────
-- NOTE: This seed data matches 001_initial_schema.sql. If you update one, update both.
ON CONFLICT (name) DO UPDATE SET
    lower_freq = EXCLUDED.lower_freq,
    upper_freq = EXCLUDED.upper_freq,
    band_group = EXCLUDED.band_group,
    warc = EXCLUDED.warc,
    is_common = EXCLUDED.is_common,
    sort_order = EXCLUDED.sort_order;


-- ─────────────────────────────────────────────────────────────────────────────
-- MODES
-- Common operating modes and ADIF mapping.
-- ─────────────────────────────────────────────────────────────────────────────
-- NOTE: This seed data matches 001_initial_schema.sql. If you update one, update both.
ON CONFLICT (name) DO UPDATE SET
    category = EXCLUDED.category,
    adif_mode = EXCLUDED.adif_mode,
    adif_submode = EXCLUDED.adif_submode,
    submodes = EXCLUDED.submodes,
    is_analog = EXCLUDED.is_analog,
    is_popular = EXCLUDED.is_popular,
    sort_order = EXCLUDED.sort_order;


-- ─────────────────────────────────────────────────────────────────────────────
-- DXCC ENTITIES
-- Source: k0swe/dxcc-json (dxcc-2020-02.csv), current entities.
-- ─────────────────────────────────────────────────────────────────────────────
ON CONFLICT (entity_id) DO UPDATE SET
    name             = EXCLUDED.name,
    lotw_entity_name = EXCLUDED.lotw_entity_name,
    prefix           = EXCLUDED.prefix,
    continent        = EXCLUDED.continent,
    cq_zone          = EXCLUDED.cq_zone,
    itu_zone         = EXCLUDED.itu_zone,
    deleted          = EXCLUDED.deleted,
    valid_from       = EXCLUDED.valid_from,
    valid_to         = EXCLUDED.valid_to;


-- ─────────────────────────────────────────────────────────────────────────────
-- DXCC PREFIX ALIASES
-- Derived from dxcc_entities + high-impact manual aliases.
-- Must run after dxcc_entities seed.
-- ─────────────────────────────────────────────────────────────────────────────
SELECT prefix, entity_id, 'dxcc_entities'
FROM (
    SELECT DISTINCT ON (UPPER(BTRIM(prefix)))
           UPPER(BTRIM(prefix)) AS prefix,
           entity_id
    FROM dxcc_entities
    WHERE NULLIF(BTRIM(prefix), '') IS NOT NULL
      AND deleted = FALSE
    ORDER BY UPPER(BTRIM(prefix)), entity_id
) deduped
ON CONFLICT (prefix) DO UPDATE
SET entity_id = EXCLUDED.entity_id,
    source = EXCLUDED.source;

    -- United States of America (DXCC 291)
    ('W', 291, 'alias'),
    ('N', 291, 'alias'),
    ('AA', 291, 'alias'),
    ('AB', 291, 'alias'),
    ('AC', 291, 'alias'),
    ('AD', 291, 'alias'),
    ('AE', 291, 'alias'),
    ('AF', 291, 'alias'),
    ('AG', 291, 'alias'),
    ('AI', 291, 'alias'),
    ('AJ', 291, 'alias'),
    ('AK', 291, 'alias'),
    ('AL', 291, 'alias'),

    -- Canada (DXCC 1)
    ('VE', 1, 'alias'),
    ('VO', 1, 'alias'),
