    ('CK', 1, 'alias'),

    -- Japan (DXCC 339)
    ('JE', 339, 'alias'),
    ('JF', 339, 'alias'),
    ('JG', 339, 'alias'),
    ('JH', 339, 'alias'),
    ('JI', 339, 'alias'),
