    ('JS', 339, 'alias'),
    ('7J', 339, 'alias'),
    ('7K', 339, 'alias'),
    ('7L', 339, 'alias'),
    ('7M', 339, 'alias'),
    ('7N', 339, 'alias'),
    ('8J', 339, 'alias')
ON CONFLICT (prefix) DO UPDATE
SET entity_id = EXCLUDED.entity_id,
    source = EXCLUDED.source;


